 15	function toArtifactIdentityKey(args: {
 16	  displayName: string;
 17	  currentVersionLabel: string | null;
 18	}): string {
 19	  return `${args.displayName}::${args.currentVersionLabel ?? ''}`;
 20	}
 21	
 22	function buildCurrentArtifacts(args: {
 23	  artifacts: ArtifactSummary[];
 24	  processId: string;
 25	}): ProcessArtifactReference[] {
 26	  return sortByUpdatedAtDesc(
 27	    args.artifacts.filter((artifact) => artifact.processId === args.processId),
 28	  ).map((artifact) => ({
 29	    artifactId: artifact.artifactId,
 30	    displayName: artifact.displayName,
 31	    currentVersionLabel: artifact.currentVersionLabel,
 32	    roleLabel: artifact.attachmentScope === 'process' ? 'Current working artifact' : null,
 33	    updatedAt: artifact.updatedAt,
 34	  }));
 35	}
 36	
 37	function buildCurrentOutputs(args: {
 38	  outputs: ProcessOutputReference[];
 39	  currentArtifacts: ProcessArtifactReference[];
 40	}): ProcessOutputReference[] {
 41	  const currentArtifactIdentities = new Set(
 42	    args.currentArtifacts.map((artifact) =>
 43	      toArtifactIdentityKey({
 44	        displayName: artifact.displayName,
 45	        currentVersionLabel: artifact.currentVersionLabel,
 46	      }),
 47	    ),
 48	  );
 49	
 50	  return sortByUpdatedAtDesc(args.outputs).filter((output) => {
 51	    if (output.state !== 'published_to_artifact') {
 52	      return true;
 53	    }
 54	
 55	    return !currentArtifactIdentities.has(
 56	      toArtifactIdentityKey({
 57	        displayName: output.displayName,
 58	        currentVersionLabel: output.revisionLabel,
 59	      }),
 60	    );
 61	  });
 62	}
 63	
 64	function buildCurrentSources(args: {
 65	  sourceAttachments: Awaited<ReturnType<PlatformStore['listProjectSourceAttachments']>>;
 66	  processId: string;
 67	}): ProcessSourceReference[] {
 68	  return sortByUpdatedAtDesc(
 69	    args.sourceAttachments.filter(
 70	      (sourceAttachment) => sourceAttachment.processId === args.processId,
 71	    ),
 72	  ).map((sourceAttachment) => ({
 73	    sourceAttachmentId: sourceAttachment.sourceAttachmentId,
 74	    displayName: sourceAttachment.displayName,
 75	    purpose: sourceAttachment.purpose,
 76	    targetRef: sourceAttachment.targetRef,
 77	    hydrationState: sourceAttachment.hydrationState,
 78	    updatedAt: sourceAttachment.updatedAt,
 79	  }));
 80	}
