 85	  async read(args: {
 86	    projectId: string;
 87	    processId: string;
 88	  }): Promise<ProcessMaterialsSectionEnvelope> {
 89	    const [artifacts, outputs, sourceAttachments] = await Promise.all([
 90	      this.platformStore.listProjectArtifacts({
 91	        projectId: args.projectId,
 92	      }),
 93	      this.platformStore.listProcessOutputs({
 94	        processId: args.processId,
 95	      }),
 96	      this.platformStore.listProjectSourceAttachments({
 97	        projectId: args.projectId,
 98	      }),
 99	    ]);
100	
101	    const currentArtifacts = buildCurrentArtifacts({
102	      artifacts,
103	      processId: args.processId,
104	    });
105	    const currentOutputs = buildCurrentOutputs({
106	      outputs,
107	      currentArtifacts,
108	    });
109	    const currentSources = buildCurrentSources({
110	      sourceAttachments,
111	      processId: args.processId,
112	    });
113	
114	    return processMaterialsSectionEnvelopeSchema.parse({
115	      status:
116	        currentArtifacts.length > 0 || currentOutputs.length > 0 || currentSources.length > 0
117	          ? 'ready'
118	          : 'empty',
119	      currentArtifacts,
120	      currentOutputs,
121	      currentSources,
122	    });
123	  }
124	}

