 12	function isStaleMessage(state: ProcessSurfaceState, message: LiveProcessUpdateMessage): boolean {
 13	  if (state.live.subscriptionId !== message.subscriptionId) {
 14	    return false;
 15	  }
 16	
 17	  if (state.live.lastSequenceNumber === null) {
 18	    return false;
 19	  }
 20	
 21	  return message.sequenceNumber <= state.live.lastSequenceNumber;
 22	}
 23	
 24	function mergeHistoryItems(
 25	  items: ProcessHistoryItem[],
 26	  nextItem: ProcessHistoryItem,
 27	): ProcessHistoryItem[] {
 28	  const deduped = items.filter((item) => item.historyItemId !== nextItem.historyItemId);
 29	  deduped.push(nextItem);
 30	  deduped.sort((left, right) => left.createdAt.localeCompare(right.createdAt));
 31	  return deduped;
 32	}
 33	
 34	function buildHistoryEnvelope(
 35	  current: ProcessHistorySectionEnvelope | null,
 36	  nextItem: ProcessHistoryItem,
 37	): ProcessHistorySectionEnvelope {
 38	  return {
 39	    status: 'ready',
 40	    items: mergeHistoryItems(current?.items ?? [], nextItem),
 41	  };
 42	}
 43	
 44	function buildSectionErrorEnvelope(
 45	  entityType: 'history' | 'materials' | 'side_work',
 46	  error: ProcessSurfaceSectionError,
 47	): ProcessHistorySectionEnvelope | ProcessMaterialsSectionEnvelope | SideWorkSectionEnvelope {
 48	  if (entityType === 'history') {
 49	    return {
 50	      status: 'error',
 51	      items: [],
 52	      error,
 53	    };
 54	  }
 55	
 56	  if (entityType === 'materials') {
 57	    return {
 58	      status: 'error',
 59	      currentArtifacts: [],
 60	      currentOutputs: [],
 61	      currentSources: [],
 62	      error,
 63	    };
 64	  }
 65	
 66	  return {
 67	    status: 'error',
 68	    items: [],
 69	    error,
 70	  };
 71	}
 72	
 73	function applyCurrentRequest(next: CurrentProcessRequest | null): CurrentProcessRequest | null {
 74	  return next;
 75	}
 76	
 77	export interface ApplyLiveProcessMessageArgs {
 78	  state: ProcessSurfaceState;
 79	  message: LiveProcessUpdateMessage;
 80	}
 81	
 82	export function applyLiveProcessMessage(args: ApplyLiveProcessMessageArgs): ProcessSurfaceState {
 83	  if (args.state.processId !== null && args.message.processId !== args.state.processId) {
 84	    return args.state;
 85	  }
 86	
 87	  if (isStaleMessage(args.state, args.message)) {
 88	    return args.state;
 89	  }
 90	
 91	  const nextState: ProcessSurfaceState = {
 92	    ...args.state,
 93	    live: {
 94	      ...args.state.live,
 95	      connectionState: 'connected',
 96	      subscriptionId: args.message.subscriptionId,
 97	      lastSequenceNumber: args.message.sequenceNumber,
 98	      error: null,
 99	    },
100	  };
101	
102	  if (args.message.messageType === 'error') {
103	    const envelope = buildSectionErrorEnvelope(args.message.entityType, args.message.payload);
104	
105	    if (args.message.entityType === 'history') {
106	      nextState.history = envelope as ProcessHistorySectionEnvelope;
107	    }
108	
109	    if (args.message.entityType === 'materials') {
110	      nextState.materials = envelope as ProcessMaterialsSectionEnvelope;
111	    }
112	
113	    if (args.message.entityType === 'side_work') {
114	      nextState.sideWork = envelope as SideWorkSectionEnvelope;
115	    }
116	
117	    return nextState;
118	  }
119	
120	  if (args.message.entityType === 'process') {
121	    nextState.process = args.message.payload;
122	    return nextState;
123	  }
124	
125	  if (args.message.entityType === 'history') {
126	    nextState.history = buildHistoryEnvelope(args.state.history, args.message.payload);
127	    return nextState;
128	  }
129	
130	  if (args.message.entityType === 'current_request') {
131	    nextState.currentRequest = applyCurrentRequest(args.message.payload);
132	    return nextState;
133	  }
134	
135	  if (args.message.entityType === 'materials') {
136	    nextState.materials = args.message.payload;
137	    return nextState;
138	  }
139	
140	  nextState.sideWork = args.message.payload;
141	  return nextState;
142	}

