39	export class ProcessModuleRegistry {
40	  private readonly modules = new Map<SupportedProcessType, ProcessWorkSurfaceModule<unknown>>();
41	
42	  constructor(modules: ProcessWorkSurfaceModule<unknown>[] = []) {
43	    for (const module of modules) {
44	      this.register(module);
45	    }
46	  }
47	
48	  register(module: ProcessWorkSurfaceModule<unknown>): void {
49	    this.modules.set(module.processType, module);
50	  }
51	
52	  get(processType: SupportedProcessType): ProcessWorkSurfaceModule<unknown> {
53	    const module = this.modules.get(processType);
54	
55	    if (module === undefined) {
56	      throw new AppError({
57	        code: story0NotImplementedErrorCode,
58	        message: `No process work-surface module is registered for ${processType}.`,
59	        statusCode: 501,
60	      });
61	    }
62	
63	    return module;
64	  }
65	
66	  list(): SupportedProcessType[] {
67	    return [...this.modules.keys()];
68	  }
69	}

